  "objectives": [],
  "questionProse": [
    "מה עושה הפונקציה `COALESCE` ב‑SQL?"
  ],
  "hintsProse": [],
  "explanationProse": [
    "הפונקציה `COALESCE` מחזירה את הערך הלא‑NULL הראשון ברשימה שצוינה, והיא שימושית להחלפת ערכי ברירת מחדל כאשר נתקלות ב‑NULL.\n\n    לדוגמה, `COALESCE(column_name, 0)` תחזיר `0` אם `column_name` הוא `NULL`."
  ]
}
